    def __init__(self, sp_entity_id, sp_single_logout_service, certificate):
        self.sp = bindings.serialize_object(bindings.SAML20Metadata(), MetadataParser.fromXMLString(config.get_metadata(entityID=sp_entity_id)).getSingleSignOnServiceByIndex(0).__xml__)
